local http = require "resty.http"
local httpc = http.new()

-- Configuration
local max_redirects = 5
local timeout = 5000
local allowed_schemes = {["http"] = true, ["https"] = true}

-- Function to validate URL
local function validate_url(url)
    if not url or type(url) ~= "string" then
        return false, "Invalid URL"
    end
    
    -- Basic URL structure check
    local scheme, host = string.match(url, "^(%w+)://([^/]+)")
    if not scheme or not host then
        return false, "Invalid URL format"
    end
    
    -- Check scheme
    if not allowed_schemes[scheme] then
        return false, "Unsupported scheme"
    end
    
    -- Check for internal IP ranges
    local ip = ngx.var.http_host or host
    if ip then
        -- Block private IP ranges
        local private_ranges = {
            "10.%d+.%d+.%d+",
            "172.(1[6-9]|2%d|3[0-1]).%d+.%d+",
            "192.168.%d+.%d+",
            "127.%d+.%d+.%d+",
            "169.254.%d+.%d+"
        }
        
        for _, pattern in ipairs(private_ranges) do
            if string.match(ip, pattern) then
                return false, "Internal IP address not allowed"
            end
        end
        
        -- Block localhost and loopback
        if string.match(ip, "^localhost$") or string.match(ip, "^127%.") then
            return false, "Localhost access not allowed"
        end
    end
    
    return true
end

-- Function to handle request
local function handle_request()
    local url = ngx.var.arg_url
    if not url then
        ngx.status = 400
        ngx.say("Missing url parameter")
        ngx.exit(400)
        return
    end
    
    -- Validate URL
    local is_valid, error_msg = validate_url(url)
    if not is_valid then
        ngx.status = 400
        ngx.say("Invalid URL: " .. error_msg)
        ngx.exit(400)
        return
    end
    
    -- Set timeout and other options
    httpc:set_timeout(timeout)
    
    -- Make request
    local res, err = httpc:request_uri(url, {
        method = ngx.var.request_method,
        headers = ngx.req.get_headers(),
        body = ngx.req.get_body_data(),
        redirect = false,
        ssl_verify = false
    })
    
    if not res then
        ngx.status = 502
        ngx.say("Failed to fetch URL: " .. err)
        ngx.exit(502)
        return
    end
    
    -- Handle redirects
    if res.status >= 300 and res.status < 400 then
        local location = res.headers["Location"]
        if location then
            -- Validate redirect URL
            local is_valid_redirect, error_msg = validate_url(location)
            if not is_valid_redirect then
                ngx.status = 400
                ngx.say("Invalid redirect URL: " .. error_msg)
                ngx.exit(400)
                return
            end
            
            -- Follow redirect with limit
            local redirect_count = 0
            local current_url = location
            
            while redirect_count < max_redirects do
                local redirect_res, redirect_err = httpc:request_uri(current_url, {
                    method = "GET",
                    headers = ngx.req.get_headers(),
                    redirect = false,
                    ssl_verify = false
                })
                
                if not redirect_res then
                    ngx.status = 502
                    ngx.say("Failed to follow redirect: " .. redirect_err)
                    ngx.exit(502)
                    return
                end
                
                if redirect_res.status >= 300 and redirect_res.status < 400 then
                    local redirect_location = redirect_res.headers["Location"]
                    if not redirect_location then
                        break
                    end
                    
                    local is_valid_redirect, error_msg = validate_url(redirect_location)
                    if not is_valid_redirect then
                        ngx.status = 400
                        ngx.say("Invalid redirect URL: " .. error_msg)
                        ngx.exit(400)
                        return
                    end
                    
                    current_url = redirect_location
                    redirect_count = redirect_count + 1
                else
                    res = redirect_res
                    break
                end
            end
        end
    end
    
    -- Send response
    ngx.status = res.status
    
    -- Copy headers
    for key, val in pairs(res.headers) do
        if key ~= "Transfer-Encoding" then
            ngx.header[key] = val
        end
    end
    
    -- Send body
    ngx.print(res.body)
end

-- Main execution
handle_request()